```class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        sort(folder.begin(), folder.end());
        vector<string> res;
        string cur = "";
        for (string s : folder) {
            if (!s.startswith(cur + "/")) {
                res.push_back(s);
                cur = s;
            }
        }
        return res;
    }
};
